import { useState } from "react";
import "../App.css"

export default function Modal({ children } : { children : React.ReactNode }) {
    

    return (
        <div>
            <div className="ModalContainer">
                <div className="ModalContent">
                    {children}
                    <button onClick={() => setShowModal(false)}>Close</button>
                </div>
            </div>
        </div>
    )
}
